import React from 'react';

function CustomParallax({ scrollPercentage, layers }) {
  return (
    <div className="CustomParallaxWrapper">
      <div className="CustomParallax">
        {layers.map((layer, index) => {
          let adjustedOffset = layer.offset;
          
          if (window.innerWidth <= 768) {
            switch (index) {
              case 0:
                adjustedOffset = '-10px';
                break;
              case 1:
                adjustedOffset = '-20px';
                break;
              case 2:
                adjustedOffset = '-30px';
                break;
              case 3:
                adjustedOffset = '-40px';
                break;
              case 4:
                adjustedOffset = '-50px';
                break;
              default:
                break;
            }
          } else if (window.innerWidth <= 576) {
            switch (index) {
              case 0:
                adjustedOffset = '-20px';
                break;
              case 1:
                adjustedOffset = '-50px';
                break;
              case 2:
                adjustedOffset = '-15px';
                break;
              case 3:
                adjustedOffset = '-20px';
                break;
              case 4:
                adjustedOffset = '-25px';
                break;
              default:
                break;
            }
          }
          
          return (
            <div
              key={index}
              className={`Layer${index + 1}`}
              style={{
                backgroundImage: `url('${layer.image}')`,
                backgroundPositionX: `calc(${scrollPercentage * layer.speed}% + ${adjustedOffset})`
              }}
            ></div>
          );
        })}
      </div>
    </div>
  );
}

export default CustomParallax;
